using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Use it to serialize
string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo returns false if not available
//    First, a type the resolver CAN handle:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
    Console.WriteLine($"TryGetTypeInfo(Person) succeeded — kind: {info!.Kind}");
else
    Console.WriteLine("TryGetTypeInfo(Person) returned false");

// Now use a resolver that only knows about Person, so int[] is unknown:
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new OnlyPersonResolver()
};

if (limited.TryGetTypeInfo(typeof(int[]), out _))
    Console.WriteLine("TryGetTypeInfo(int[]) succeeded");
else
    Console.WriteLine("TryGetTypeInfo(int[]) returned false — metadata not available");

// --- Types ---
record Person(string Name, int Age);

// A custom resolver that only provides metadata for Person
sealed class OnlyPersonResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

